+                &agent("Receiver"),
+                MessageKind::Info,
+                json!(i),
+            );
+        }
+        let msgs = hub.inbox(&agent("Receiver"));
+        assert_eq!(msgs.len(), 5);
+        // Messages should be in insertion order.
